module rc_oscillator (
    input wire clk,
    input wire rst,
    input wire enable,
    output reg out
);
    reg [23:0] obf_counter;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            obf_counter <= 0;
            out <= 0;
        end else if (enable) begin
            if (obf_counter == 24'd12499999) begin // Adjust this value for frequency
                out <= ~out;
                obf_counter <= 0;
            end else begin
                obf_counter <= obf_counter + 1;
            end
        end else begin
            out <= 0; // Disable output when not enabled
        end
    end
endmodule
